For Q2 there is a much faster O(n*log(n)) solution using some tricks: priority queue to keep the peaks, and a linked list to store the sequence. If you delete a peak then check its neighbors to see if we can get new peaks. [I have already posted this solution].
```
class Solution{

class Node{
public:
    Node* prev;
    Node* next;
    int val;

    Node(int _val){
        val=_val;
        prev=NULL;
        next=NULL;
    }
};

private:
    Node* firstnode;
    Node* lastnode;
public:

   vector<int> deleteMinimalPeaks(vector<int> v){

       int n=v.size();
       vector<int>ans;
       unordered_map<int,Node*> mymap;

       firstnode=new Node(0);
       lastnode=new Node(0);
       firstnode->next=lastnode;
       lastnode->prev=firstnode;

       for(int x:v){
           Node* mynode=new Node(x);
           mymap[x]=mynode;
           addNode(mynode);
       }

       priority_queue<int,vector<int>,greater<int>> pq;
       for(int i=0;i<n;i++)
           if(peak(v[i],mymap)) pq.push(v[i]);

       for(int it=0;it<n;it++){
           int x=pq.top();
           pq.pop();
           ans.push_back(x);

           Node* nd=mymap[x];
           int v0=nd->prev->val;
           int v1=nd->next->val;
           delNode(nd);
           if(nd->prev!=firstnode && peak(v0,mymap))pq.push(v0);
           if(nd->next!=lastnode && peak(v1,mymap))pq.push(v1);
       }
       return ans;
   }

   bool peak(int x,unordered_map<int,Node*>& mymap){

       Node* n=mymap[x];

       if(n!=firstnode && x<n->prev->val)return false;
       if(n!=lastnode &&  x<n->next->val)return false;
       return true;
   }

   void delNode(Node* delnode){

       delnode->prev->next=delnode->next;
       delnode->next->prev=delnode->prev;
   }

   void addNode(Node* addnode){

       lastnode->prev->next=addnode;
       addnode->prev=lastnode->prev;
       addnode->next=lastnode;
       lastnode->prev=addnode;
   }
};

Solution of Q3. Observe that the number or rounds will be the same no matter of the players choice [it would be good to see a proof for this, math related stuff].
If we accept this then the solution is trivial, runs in O(n) time using stack.
```
string winner(vector<int> v){

    stack<int>S;

    for(int x:v){
        if(!S.empty() && S.top()==x)  S.pop();
        else S.push(x);
    }

    return ((v.size()-S.size())/2)%2==1?"Player 1":"Player 2";
}

int main(void){

    cout<<winner({1,0,1,0,0,1,0})<<endl;

    return 0;
}
