Question 1:
Doing an in-place rotation.
```
	public int[][] rotate_without_extra_space(int[][] matrix) {
		int n = matrix.length;
		// transpose matrix
		for (int i = 0; i < n; i++) {
			for (int j = i; j < n; j++) {
				if (i == j || i + j == matrix.length - 1) {
					//Diagonal
				} else {
					int tmp = matrix[j][i];
					matrix[j][i] = matrix[i][j];
					matrix[i][j] = tmp;
				}
			}
		}
		// reverse each row
		for (int i = 0; i < n; i++) {
			for (int j = 0; j < n / 2; j++) {
				if (i == j || i + j == matrix.length - 1) {
					//Diagonal
				} else {
					int tmp = matrix[i][j];
					matrix[i][j] = matrix[i][n - j - 1];
					matrix[i][n - j - 1] = tmp;
				}
			}
		}
		return matrix;
	}
