Q2 solution:-
vector<int> solution(vector<int>& v){
v.insert(v.begin(),-1e9);
v.insert(v.end(),-1e9);
stack<int> st;
st.push(v[0]);
st.push(v[1]);
vector<int> res;
for(int i=2;i<v.size();i++){
if(st.top()==-1e9){st.push(v[i]); continue;}
int mid=st.top();
st.pop();
if(mid>st.top() && mid>v[i]){
res.push_back(mid);
i--;
}
else{
st.push(mid);
st.push(v[i]);
}
}
return res;
}


Q3 solution:-
void solution(vector<int>& A){
int cnt=0;
stack<int> st;
for(int i=0;i<A.size();i++){
if(!st.empty()){
if(st.top()==A[i]){st.pop(); cnt++;}
else{st.push(A[i]);}
}
else{st.push(A[i]);}
}
if(cnt%2==0){cout<<"Player 2";}
else{cout<<"Player 1";}
}
